```class Solution {
public:
    int minMovesToMakePalindrome(string s) {
        int n = s.size();
        int res = 0;
        int l = 0, r = n - 1;
        while (l < r) {
            if (s[l] != s[r]) {
                int k = r;
                while (s[l] != s[k]) k--;
                swap(s[k], s[r]);
                res += r - k;
            }
            l++, r--;
        }
        return res;
    }
};
